/*!50003 CREATE*/ /*!50017 DEFINER=`admin`@`%`*/ /*!50003 TRIGGER `trg_order_details_after_insert` AFTER INSERT ON `order_details` FOR EACH ROW BEGIN
    -- 1. Cập nhật tổng tiền đơn hàng (Logic cũ của bạn)
    CALL update_order_totals(NEW.order_id);
    
    -- 2. Trừ tồn kho sản phẩm (Truyền vào số âm của số lượng vừa mua)
    CALL update_stock_quantity(NEW.variant_id, -NEW.quantity);

END */;;
DELIMITER ;
