DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`admin`@`%`*/ /*!50003 TRIGGER `trg_order_details_after_update` AFTER UPDATE ON `order_details` FOR EACH ROW BEGIN
    -- 1. Cập nhật tổng tiền đơn hàng
    CALL update_order_totals(OLD.order_id);
    IF OLD.order_id != NEW.order_id THEN
        CALL update_order_totals(NEW.order_id);
    END IF;

    -- 2. Cập nhật lại tồn kho
    IF OLD.variant_id = NEW.variant_id THEN
        -- Trường hợp 1: Khách chỉ đổi số lượng của cùng một món
        -- Công thức: Kho mới = Kho hiện tại + (Số lượng cũ - Số lượng mới)
        CALL update_stock_quantity(NEW.variant_id, OLD.quantity - NEW.quantity);
    ELSE
        -- Trường hợp 2: Khách đổi sang một biến thể/sản phẩm khác (variant_id bị thay đổi)
        -- Hoàn lại kho cho món cũ
        CALL update_stock_quantity(OLD.variant_id, OLD.quantity);
        -- Trừ kho cho món mới
        CALL update_stock_quantity(NEW.variant_id, -NEW.quantity);
    END IF;

END */;;
DELIMITER ;
