/*!50003 CREATE*/ /*!50017 DEFINER=`admin`@`%`*/ /*!50003 TRIGGER `trg_order_details_after_delete` AFTER DELETE ON `order_details` FOR EACH ROW BEGIN
    -- 1. Cập nhật tổng tiền đơn hàng
    CALL update_order_totals(OLD.order_id);
    
    -- 2. Hoàn lại tồn kho cho sản phẩm bị xóa (Truyền vào số lượng cũ)
    CALL update_stock_quantity(OLD.variant_id, OLD.quantity);

END */;;
DELIMITER ;
