/*!50003 CREATE*/ /*!50017 DEFINER=`admin`@`%`*/ /*!50003 TRIGGER `trg_orders_before_update` BEFORE UPDATE ON `orders` FOR EACH ROW BEGIN

    SET NEW.total_amount =

        NEW.subtotal

        - (
            NEW.subtotal
            * NEW.discount_rate / 100
        )

        + (
            (
                NEW.subtotal
                - (
                    NEW.subtotal
                    * NEW.discount_rate / 100
                )
            )
            * NEW.tax_rate / 100
        )

        + NEW.shipping_fee;

END */;;
DELIMITER ;
