/*!50003 CREATE*/ /*!50017 DEFINER=`admin`@`%`*/ /*!50003 TRIGGER `trg_orders_after_update_status` AFTER UPDATE ON `orders` FOR EACH ROW BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_variant_id INT;
    DECLARE v_quantity INT;
    
    -- Lấy danh sách các mặt hàng trong đơn bị hủy
    DECLARE cur CURSOR FOR SELECT variant_id, quantity FROM order_details WHERE order_id = NEW.order_id;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- Nếu trạng thái đơn hàng bị đổi thành 'cancelled'
    IF OLD.order_status != 'cancelled' AND NEW.order_status = 'cancelled' THEN
        OPEN cur;
        read_loop: LOOP
            FETCH cur INTO v_variant_id, v_quantity;
            IF done THEN LEAVE read_loop; END IF;
            
            -- Hoàn lại kho cho từng mặt hàng
            CALL update_stock_quantity(v_variant_id, v_quantity);
        END LOOP;
        CLOSE cur;
    END IF;
END */;;
DELIMITER ;
