/*!50003 SET sql_mode              = 'REAL_AS_FLOAT,PIPES_AS_CONCAT,ANSI_QUOTES,IGNORE_SPACE,ONLY_FULL_GROUP_BY,ANSI,STRICT_TRANS_TABLES,STRICT_ALL_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`avnadmin`@`%`*/ /*!50003 TRIGGER `trg_payments_after_update` AFTER UPDATE ON `payments` FOR EACH ROW BEGIN
    -- Nếu giao dịch chuyển sang trạng thái thất bại 'failed'
    IF OLD.payment_status != 'failed' AND NEW.payment_status = 'failed' THEN
        -- Chuyển trạng thái đơn sang 'cancelled' (Từ đây Trigger 5 sẽ tự động tiếp quản việc hoàn kho)
        UPDATE orders 
        SET order_status = 'cancelled' 
        WHERE order_id = NEW.order_id AND order_status != 'cancelled';
    END IF;
END */;;
DELIMITER ;
