INSERT INTO `products` VALUES ('101','Nike Mercurial Vapor 17','Siêu phẩm cho các tiền đạo tốc độ, với công nghệ đệm Zoom Air độc quyền giúp tối ưu hóa khả năng bứt tốc và xoay sở trong phạm vi hẹp trên sân cỏ nhân tạo.',3200000,'2026-05-20 08:00:00',1),('102','Nike Mercurial Vapor 16','Phiên bản cải tiến với phần thân trên làm từ sợi Vaporposite+, mang lại cảm giác bóng chân thật nhất và hỗ trợ ôm sát bàn chân khi di chuyển với cường độ cao.',2800000,'2026-05-20 08:05:00',1),('103','Nike Mercurial Vapor 15','Thiết kế khí động học lấy cảm hứng từ đôi cánh, giúp giảm tối đa lực cản gió khi chạy, kết hợp cùng bộ đế đinh TF bám sân cực tốt.',2500000,'2026-05-20 08:10:00',1),('104','Nike Mercurial Vapor 13','Dòng giày kinh điển với chất liệu tổng hợp bền bỉ, mang lại sự ổn định tuyệt đối cho các cầu thủ cần một đôi giày không bao giờ lỗi thời.',2000000,'2026-05-20 08:15:00',1),('105','Nike Mercurial Superfly','Cổ cao Dynamic Fit ôm trọn mắt cá, bảo vệ tối đa và tạo sự liên kết liền mạch giữa chân và giày, hỗ trợ các pha bứt tốc mạnh mẽ nhất.',3500000,'2026-05-20 08:20:00',1),('106','Nike Mercurial Vic 6','Lựa chọn hoàn hảo cho người mới bắt đầu với thiết kế lấy cảm hứng từ dòng cao cấp, độ bền cực cao và trọng lượng nhẹ giúp di chuyển dễ dàng.',1500000,'2026-05-20 08:25:00',1),('107','Nike Phantom 6','Vũ khí tối thượng cho các tiền vệ kiến thiết, với bề mặt vân nổi giúp tăng độ ma sát khi tiếp xúc bóng, hỗ trợ các đường chuyền chính xác đến từng milimet.',3000000,'2026-05-20 08:30:00',1),('201','Adidas Predator 26','Thế hệ Predator mới nhất với công nghệ Strikeskin trên thân giày, giúp cầu thủ kiểm soát bóng, sút xoáy và dứt điểm uy lực hơn bao giờ hết.',3400000,'2026-05-20 09:00:00',2),('202','Adidas Predator 25','Kết hợp giữa truyền thống và hiện đại, phần đệm Hybridfeel mềm mại mang lại cảm giác êm ái khi tiếp bóng, giảm thiểu chấn động cho lòng bàn chân.',2900000,'2026-05-20 09:05:00',2),('203','Adidas Predator Freak','Bộ đế được thiết kế đặc biệt với các đinh tam giác xoay, giúp bám sân tốt trong mọi điều kiện thời tiết, kể cả khi mặt sân trơn trượt.',2600000,'2026-05-20 09:10:00',2),('204','Adidas F50','Huyền thoại tốc độ trở lại với trọng lượng siêu nhẹ, chất liệu sợi dệt đàn hồi giúp đôi chân luôn cảm thấy thông thoáng trong suốt 90 phút thi đấu.',3100000,'2026-05-20 09:15:00',2),('205','Adidas X Crazyfast','Đôi giày dành cho những cầu thủ \"không thể bắt kịp\", với phần khung đế siêu cứng cáp giúp truyền lực tối đa từ từng bước chạy của bạn.',3300000,'2026-05-20 09:20:00',2),('206','Adidas X 19','Thiết kế tối giản không dây giúp tăng bề mặt tiếp xúc bóng, phù hợp cho những cầu thủ có lối đá hoa mỹ và ưa thích các pha đi bóng lắt léo.',2100000,'2026-05-20 09:25:00',2),('207','Adidas Copa Pure','Sử dụng da bê cao cấp, mang lại cảm giác bóng êm như nhung, một lựa chọn tuyệt vời cho lối đá thiên về kỹ thuật và sự mềm mại.',2500000,'2026-05-20 09:30:00',2),('301','Puma Future','Công nghệ Netfit cho phép tùy chỉnh dây giày theo hình dáng bàn chân, đảm bảo sự vừa vặn tuyệt đối và khóa chặt gót chân khi tăng tốc đột ngột.',2700000,'2026-05-20 10:00:00',3),('302','Puma Ultra','Sử dụng sợi dệt MATRYXEVO siêu nhẹ và bền, biến đôi giày này trở thành đôi giày nhanh nhất trên thị trường, giúp bạn dẫn trước đối thủ một bước chân.',2900000,'2026-05-20 10:05:00',3),('303','Puma King','Biểu tượng của da thật, với bề mặt da Kangaroo cao cấp mang lại sự thoải mái tự nhiên, cho phép đôi giày ôm sát bàn chân theo thời gian sử dụng.',3000000,'2026-05-20 10:10:00',3),('304','Puma One','Sự cân bằng hoàn hảo giữa tốc độ, kiểm soát và sự êm ái, một đôi giày toàn diện cho mọi vị trí trên sân cỏ nhân tạo.',2200000,'2026-05-20 10:15:00',3),('305','Puma Evospeed','Thiết kế tối giản tập trung vào việc giảm thiểu trọng lượng, giúp giảm mỏi chân khi thi đấu thời gian dài trên các mặt sân cỏ nhân tạo.',2400000,'2026-05-20 10:20:00',3),('306','Puma Match','Độ bền vượt trội với lớp bảo vệ mũi giày được gia cố, phù hợp cho những trận đấu \"phủi\" khắc nghiệt và cường độ tranh chấp bóng cao.',1800000,'2026-05-20 10:25:00',3),('307','Puma Solarthon','Sự kết hợp giữa thời trang và công năng, lưới thoáng khí giúp đôi chân luôn khô ráo trong suốt trận đấu dưới tiết trời nóng nực.',1900000,'2026-05-20 10:30:00',3),('401','Mizuno Morelia Neo','Đỉnh cao của sự tinh tế Nhật Bản, sự kết hợp giữa da Kangaroo cao cấp và công nghệ đế hiện đại, nhẹ nhàng như đang đi chân trần.',4000000,'2026-05-20 11:00:00',4),('402','Mizuno Alpha Pro','Dòng giày tốc độ cao nhất của Mizuno với công nghệ vải dệt mới nhất, hỗ trợ di chuyển linh hoạt và bứt tốc cực nhanh trên sân cỏ.',3500000,'2026-05-20 11:05:00',4),('403','Mizuno Sala Beta','Thiết kế chuyên dụng cho Futsal, với đế ngoài có độ bám sàn tuyệt đối và phần đệm giảm chấn hỗ trợ tốt cho đôi chân trên mặt sàn cứng.',2800000,'2026-05-20 11:10:00',4),('404','Mizuno Morelia II','Dòng giày huyền thoại không bao giờ lỗi mốt, mang lại sự ổn định và cảm giác bóng chuẩn xác cho những tín đồ của trường phái kỹ thuật.',3200000,'2026-05-20 11:15:00',4),('405','Mizuno Monarcida','Sự lựa chọn phổ thông nhưng vẫn giữ được chất lượng Mizuno, form giày cực kỳ ôm chân, phù hợp với hầu hết kiểu bàn chân của người Việt.',1500000,'2026-05-20 11:20:00',4),('406','Mizuno Rebula','Công nghệ ổn định bàn chân tích hợp, giúp giữ thăng bằng tốt hơn trong các tình huống xoay sở, lừa bóng trong không gian hẹp.',2500000,'2026-05-20 11:25:00',4),('407','Mizuno Wave Cup','Phiên bản kỷ niệm đặc biệt, mang hơi hướng cổ điển nhưng được tích hợp công nghệ đệm Wave hiện đại, mang lại sự êm ái chưa từng có.',4500000,'2026-05-20 11:30:00',4),('501','Kamito Velocidad','Dòng sản phẩm \"quốc dân\" trên sân phủi, với bề mặt da tổng hợp chống nước tốt và trọng lượng nhẹ giúp chạy nhanh hơn.',800000,'2026-05-20 12:00:00',5),('502','Kamito Taco','Form giày thiết kế riêng cho bàn chân bè của người Việt, tạo cảm giác thoải mái ngay lần đầu xỏ chân mà không gây đau tức.',750000,'2026-05-20 12:05:00',5),('503','Kamito ST11','Đế TF với các đinh dăm được sắp xếp khoa học, giúp tăng độ bám sân trong các tình huống tranh chấp bóng quyết liệt trên sân cỏ nhân tạo.',700000,'2026-05-20 12:10:00',5),('504','Kamito Cobra','Thiết kế lấy cảm hứng từ loài rắn, bề mặt vân nổi giúp tăng lực sút và độ xoáy cho mỗi cú dứt điểm.',850000,'2026-05-20 12:15:00',5),('505','Kamito IMortal','Đúng như tên gọi, sự bền bỉ được đặt lên hàng đầu với vật liệu cao cấp, chịu được các điều kiện thời tiết khắc nghiệt tại Việt Nam.',650000,'2026-05-20 12:20:00',5),('506','Kamito Archery','Sự cân bằng giữa tấn công và phòng thủ, đế giày êm ái giúp bạn duy trì năng lượng suốt trận đấu mà không bị đau mỏi.',600000,'2026-05-20 12:25:00',5),('507','Kamito Legend','Phong cách retro pha lẫn công nghệ hiện đại, mang lại vẻ ngoài ấn tượng và hiệu suất cao cho mọi cầu thủ trên sân.',900000,'2026-05-20 12:30:00',5),('601','Jogarbola JG-2212','Mẫu giày chủ lực của Jogarbola với thiết kế thời thượng, hỗ trợ đắc lực cho những cầu thủ ưa thích lối đá phối hợp ngắn và tốc độ.',650000,'2026-05-20 13:00:00',6),('602','Jogarbola JG-2215','Nâng cấp đáng kể ở bộ đế, giúp tăng khả năng đàn hồi và hỗ trợ bật nhảy, phù hợp cho những cầu thủ không chiến hoặc tranh chấp tầm cao.',700000,'2026-05-20 13:05:00',6),('603','Jogarbola JG-2220','Đôi giày siêu nhẹ, giúp bạn dễ dàng bứt tốc và tạo sự khác biệt trong những khoảnh khắc quyết định của trận đấu.',720000,'2026-05-20 13:10:00',6),('604','Jogarbola JG-2230','Da microfiber mềm mại mô phỏng da thật, mang lại cảm giác bóng cực tốt và độ bền cao cho người sử dụng thường xuyên.',800000,'2026-05-20 13:15:00',6),('605','Jogarbola Evolution','Đôi giày đa năng với khả năng thích nghi cao trên nhiều bề mặt sân, từ sân cỏ nhân tạo đến sân bê tông, sân trong nhà.',550000,'2026-05-20 13:20:00',6),('606','Jogarbola Classic','Đơn giản, tinh tế và hiệu quả, đây là sự lựa chọn an toàn cho mọi cầu thủ cần một đôi giày \"nồi đồng cối đá\".',500000,'2026-05-20 13:25:00',6),('607','Jogarbola Pro','Dòng cao cấp hơn với công nghệ đệm êm, bảo vệ tối đa các khớp xương chân khi phải thi đấu trên mặt sân cứng.',950000,'2026-05-20 13:30:00',6),('701','Wika W-Speed','Tốc độ là điểm nhấn, thiết kế thon gọn giúp bạn luồn lách qua các hàng phòng ngự một cách dễ dàng.',550000,'2026-05-20 14:00:00',7),('702','Wika Neo','Phong cách hiện đại với phối màu nổi bật, thu hút mọi ánh nhìn trên sân cỏ.',600000,'2026-05-20 14:05:00',7),('703','Wika Siêu nhẹ','Trọng lượng tối ưu giúp bạn duy trì tốc độ xuyên suốt trận đấu mà không cảm thấy nặng chân.',650000,'2026-05-20 14:10:00',7),('704','Wika CP','Bền bỉ vượt trội nhờ vật liệu tổng hợp chất lượng cao, xứng đáng là người bạn đồng hành tin cậy trên sân phủi.',500000,'2026-05-20 14:15:00',7),('705','Wika H2','Đế chắc chắn, khả năng bám sân tốt giúp bạn tự tin thực hiện các pha xoay trở đột ngột.',580000,'2026-05-20 14:20:00',7),('706','Wika Ultimate','Cao cấp nhất trong dòng Wika, tích hợp những công nghệ mới nhất để mang lại hiệu năng thi đấu cao nhất.',700000,'2026-05-20 14:25:00',7),('707','Wika T-01','Dòng giày khởi đầu với mức giá dễ tiếp cận, nhưng vẫn đảm bảo đầy đủ các tính năng cơ bản cần thiết cho một trận bóng đá.',450000,'2026-05-20 14:30:00',7),('801','Zocker Inspire','Thiết kế ergonomic ôm sát bàn chân, giúp giảm ma sát và chống phồng rộp khi thi đấu cường độ cao.',750000,'2026-05-20 15:00:00',8),('802','Zocker Space','Form ôm chân cực tốt, tạo cảm giác như một phần của cơ thể, hỗ trợ tối đa các pha sút bóng chính xác.',780000,'2026-05-20 15:05:00',8),('803','Zocker Action','Linh hoạt trong từng bước chạy, giúp cầu thủ dễ dàng thay đổi hướng và bắt kịp mọi diễn biến trên sân.',720000,'2026-05-20 15:10:00',8),('804','Zocker Z-Pro','Khả năng bám sân ấn tượng, giúp bạn đứng vững trong các tình huống tranh chấp bóng tay đôi.',850000,'2026-05-20 15:15:00',8),('805','Zocker Turbo','Tốc độ cực nhanh nhờ phần đế được thiết kế tối ưu hóa cho những pha tăng tốc tức thời.',800000,'2026-05-20 15:20:00',8),('806','Zocker Energy','Mang lại năng lượng dồi dào, giúp bạn duy trì phong độ ổn định ngay cả trong những phút cuối cùng của trận đấu.',680000,'2026-05-20 15:25:00',8),('807','Zocker Fly','Cảm giác bay bổng khi di chuyển nhờ trọng lượng nhẹ và thiết kế tinh tế, giúp bạn tự tin thể hiện kỹ năng.',900000,'2026-05-20 15:30:00',8),('901','Kelme Precision','Huyền thoại làng Futsal, với đế ngoài bám sàn đỉnh cao và độ bền đáng kinh ngạc, lựa chọn số 1 cho các giải đấu trong nhà.',950000,'2026-05-20 16:00:00',9),('902','Kelme Villacampa','Da lộn cao cấp mang lại vẻ ngoài sang trọng và cảm giác bóng vô cùng chân thật, thường được các danh thủ tin dùng.',1100000,'2026-05-20 16:05:00',9),('903','Kelme Star','Đế giày cứng cáp, bảo vệ bàn chân trước những tác động mạnh trên mặt sân bê tông hay sân Futsal.',850000,'2026-05-20 16:10:00',9),('904','Kelme Indoor','Dòng giày dành riêng cho mặt sàn trong nhà, đảm bảo sự linh hoạt tối đa cho các pha đi bóng lắt léo.',900000,'2026-05-20 16:15:00',9),('905','Kelme K-Stellar','Kết hợp giữa công nghệ hiện đại và thiết kế tối ưu, giúp nâng tầm kỹ năng chơi bóng của bạn lên một đẳng cấp mới.',1200000,'2026-05-20 16:20:00',9),('906','Kelme Street','Thời trang, trẻ trung và năng động, không chỉ dùng để đá bóng mà còn cực hợp để dạo phố sau trận đấu.',750000,'2026-05-20 16:25:00',9),('907','Kelme Futsal Elite','Phiên bản chuyên nghiệp với đệm giảm chấn cao cấp, giúp đôi chân bạn luôn thoải mái ngay cả sau những trận đấu căng thẳng nhất.',1300000,'2026-05-20 16:30:00',9);
