CREATE DEFINER="avnadmin"@"%" PROCEDURE "get_or_create_customer"(
    IN p_first_name VARCHAR(50),
    IN p_last_name VARCHAR(50),
    IN p_phone VARCHAR(20),
    IN p_email VARCHAR(100),
    IN p_address TEXT,
    OUT p_customer_id INT -- Tham số đầu ra chứa ID khách hàng
)
BEGIN
    -- 1. Chạy lệnh INSERT. Nếu EMAIL đã tồn tại (đụng độ UNIQUE), 
    -- dòng UPDATE ngầm sẽ kích hoạt để lấy lại chính ID của khách hàng đó.
    INSERT INTO customers (first_name, last_name, phone, email, address, is_member)
    VALUES (p_first_name, p_last_name, p_phone, p_email, p_address, FALSE)
    ON DUPLICATE KEY UPDATE 
        -- Mẹo kinh điển: Gán lại ID bằng chính nó và ép LAST_INSERT_ID nhận giá trị này
        customer_id = LAST_INSERT_ID(customer_id),
        -- Cập nhật lại số điện thoại hoặc địa chỉ mới nhất nếu khách có thay đổi khi mua guest
        phone = IFNULL(p_phone, phone),
        address = IFNULL(p_address, address);

    -- 2. Gán ID vừa tìm được hoặc vừa tạo mới vào tham số đầu ra
    SET p_customer_id = LAST_INSERT_ID();
END ;;
DELIMITER ;
