CREATE DEFINER="avnadmin"@"%" PROCEDURE "guest_create_payment"(
    IN p_order_id INT,
    IN p_customer_id INT,
    IN p_payment_method_id INT
)
BEGIN
    DECLARE v_order_exists INT;
    DECLARE v_total_amount DECIMAL(15,0);
    DECLARE v_payment_exists INT;

    -- 1. Kiểm tra đơn hàng có tồn tại và thuộc về đúng khách hàng không
    SELECT COUNT(*), total_amount INTO v_order_exists, v_total_amount
    FROM orders
    WHERE order_id = p_order_id AND customer_id = p_customer_id;

    IF v_order_exists = 0 THEN
        SIGNAL SQLSTATE '45000' 
        SET MESSAGE_TEXT = 'Đơn hàng không tồn tại hoặc không thuộc quyền sở hữu của bạn.';
    END IF;

    -- 2. Kiểm tra xem đơn hàng đã có thanh toán chưa (để tránh tạo trùng)
    SELECT COUNT(*) INTO v_payment_exists
    FROM payments WHERE order_id = p_order_id;

    IF v_payment_exists > 0 THEN
        SIGNAL SQLSTATE '45000' 
        SET MESSAGE_TEXT = 'Đơn hàng này đã tồn tại bản ghi thanh toán.';
    END IF;

    -- 3. Thực hiện Insert
    INSERT INTO payments (order_id, payment_method_id, amount, payment_status)
    VALUES (p_order_id, p_payment_method_id, v_total_amount, 'pending');
END ;;
DELIMITER ;
