DELIMITER ;;
CREATE DEFINER="admin"@"%" PROCEDURE "update_order_totals"(
    IN p_order_id INT
)
BEGIN

    DECLARE v_subtotal DECIMAL(15,0);

    DECLARE v_discount_rate DECIMAL(5,2);

    DECLARE v_tax_rate DECIMAL(5,2);

    DECLARE v_shipping_fee DECIMAL(15,0);

    DECLARE v_total DECIMAL(15,0);

    -- =========================
    -- CALCULATE SUBTOTAL
    -- =========================

    SELECT
        IFNULL(SUM(quantity * unit_price), 0)
    INTO v_subtotal
    FROM order_details
    WHERE order_id = p_order_id;

    -- =========================
    -- GET ORDER INFO
    -- =========================

    SELECT
        discount_rate,
        tax_rate,
        shipping_fee
    INTO
        v_discount_rate,
        v_tax_rate,
        v_shipping_fee
    FROM orders
    WHERE order_id = p_order_id;

    -- =========================
    -- CALCULATE TOTAL
    -- =========================

    SET v_total =
        v_subtotal
        - (v_subtotal * v_discount_rate / 100)

        + (
            (
                v_subtotal
                - (v_subtotal * v_discount_rate / 100)
            )
            * v_tax_rate / 100
        )

        + v_shipping_fee;

    -- =========================
    -- UPDATE ORDERS
    -- =========================

    UPDATE orders
    SET
        subtotal = v_subtotal,
        total_amount = v_total
    WHERE order_id = p_order_id;

END ;;
DELIMITER ;
