CREATE DEFINER="admin"@"%" PROCEDURE "update_stock_quantity"(
    IN p_variant_id INT,
    IN p_quantity_change INT
)
BEGIN
    -- Cộng số lượng thay đổi vào tồn kho hiện tại
    -- Nếu mua hàng: p_quantity_change là số âm (ví dụ: -2) -> Kho giảm
    -- Nếu hủy hàng/xóa món: p_quantity_change là số dương (ví dụ: +2) -> Kho tăng
    UPDATE variants
    SET stock_quantity = stock_quantity + p_quantity_change
    WHERE variant_id = p_variant_id;
END ;;
DELIMITER ;
